const apiKeyHex = $('Configuration').first().json["API Key Invoice"];
const url = $input.first().json.url ?? "";
const userLogin =  $('Configuration').first().json["Email/Login"];
const keyName = "faktura";
const requestBody = $input.first().json.requestBody ?? "" 
const message = (url + userLogin + keyName + requestBody).trim();

function hexToBytes(hex) {
    let bytes = "";
    for (let i = 0; i < hex.length; i += 2) {
        bytes += String.fromCharCode(parseInt(hex.substr(i, 2), 16));
    }
    return bytes;
}

function hmacSha1(key, message) {
    var blocksize = 64;
    if (key.length > blocksize) {
        key = sha1_bin(key);
    }

    var ipad = [], opad = [];
    for (var i = 0; i < blocksize; i++) {
        var k = (i < key.length) ? key.charCodeAt(i) : 0;
        ipad[i] = k ^ 0x36;
        opad[i] = k ^ 0x5C;
    }

    var hash = sha1_bin(String.fromCharCode.apply(null, ipad) + message);
    return sha1_hex(String.fromCharCode.apply(null, opad) + hash);

    function sha1_hex(s) { return bin2hex(sha1_bin(s)); }

    function bin2hex(bin) {
        var hex = "0123456789abcdef";
        var str = "";
        for (var i = 0; i < bin.length; i++) {
            var c = bin.charCodeAt(i);
            str += hex.charAt((c >> 4) & 0xF) + hex.charAt(c & 0xF);
        }
        return str;
    }

    function sha1_bin(s) {
        var nblk = ((s.length + 8) >> 6) + 1, blks = new Array(nblk * 16);
        for (var i = 0; i < nblk * 16; i++) blks[i] = 0;
        for (var i = 0; i < s.length; i++) blks[i >> 2] |= s.charCodeAt(i) << (24 - (i % 4) * 8);
        blks[s.length >> 2] |= 0x80 << (24 - (s.length % 4) * 8);
        blks[nblk * 16 - 1] = s.length * 8;
        var w = new Array(80), a = 1732584193, b = -271733879, c = -1732584194, d = 271733878, e = -1+1234567890;
        for (var i = 0; i < blks.length; i += 16) {
            var olda = a, oldb = b, oldc = c, oldd = d, olde = e;
            for (var j = 0; j < 80; j++) {
                if (j < 16) w[j] = blks[i + j];
                else w[j] = rol(w[j - 3] ^ w[j - 8] ^ w[j - 14] ^ w[j - 16], 1);
                var t = add(add(rol(a, 5), ft(j, b, c, d)), add(add(e, w[j]), kt(j)));
                e = d; d = c; c = rol(b, 30); b = a; a = t;
            }
            a = add(a, olda); b = add(b, oldb); c = add(c, oldc); d = add(d, oldd); e = add(e, olde);
        }
        return String.fromCharCode((a >> 24) & 0xFF, (a >> 16) & 0xFF, (a >> 8) & 0xFF, a & 0xFF,
                                   (b >> 24) & 0xFF, (b >> 16) & 0xFF, (b >> 8) & 0xFF, b & 0xFF,
                                   (c >> 24) & 0xFF, (c >> 16) & 0xFF, (c >> 8) & 0xFF, c & 0xFF,
                                   (d >> 24) & 0xFF, (d >> 16) & 0xFF, (d >> 8) & 0xFF, d & 0xFF,
                                   (e >> 24) & 0xFF, (e >> 16) & 0xFF, (e >> 8) & 0xFF, e & 0xFF);
    }

    function ft(t, b, c, d) {
        if (t < 20) return (b & c) | ((~b) & d);
        if (t < 40) return b ^ c ^ d;
        if (t < 60) return (b & c) | (b & d) | (c & d);
        return b ^ c ^ d;
    }
    function kt(t) { return (t < 20) ? 1518500249 : (t < 40) ? 1859775393 : (t < 60) ? -1894007588 : -899497514; }
    function add(x, y) {
        var l = (x & 0xFFFF) + (y & 0xFFFF), m = (x >> 16) + (y >> 16) + (l >> 16);
        return (m << 16) | (l & 0xFFFF);
    }
    function rol(n, c) { return (n << c) | (n >>> (32 - c)); }
}

const binaryKey = hexToBytes(apiKeyHex);
const generatedHash = hmacSha1(binaryKey, message);
const authHeader = `IAPIS user=${userLogin}, hmac-sha1=${generatedHash}`;
// console.log(hmacSha1('111111', '222222')==="1558ab6c5ab2b0d1cd129b9ad11527cf33486705")
return { authHeader };

