        <tr style="border-top: 2px solid #dddddd;">
          <td style="padding-top: 15px;">Outstanding Amount:</td>
          <td class="amount-due" style="padding-top: 15px;">{{$json.Brutto}} {{ $json.Waluta }}</td>
        </tr>
        <tr>
          <td>Late Payment Interest:</td>
          <td class="overdue-status">+ Interest accruing daily</td>
        </tr>
      </table>
    </div>

    <!-- Legal Warning -->
    <div class="legal-warning">
      <h2>Legal Consequences Notice</h2>
      <p><strong>We hereby formally notify you of our intent to pursue legal action if this matter is not resolved immediately.</strong></p>

      <p>Failure to settle this debt within the deadline specified below will result in:</p>
      <ul>
        <li><strong>Commencement of legal proceedings</strong> in the appropriate court of law</li>
        <li><strong>Additional legal costs and court fees</strong> added to the outstanding amount</li>
        <li><strong>Statutory interest charges</strong> continuing to accrue on the unpaid balance</li>
        <li><strong>Debt collection agency involvement</strong> and potential credit reporting</li>
        <li><strong>Enforcement of judgment</strong> through asset seizure or wage garnishment</li>
        <li><strong>Damage to your business credit rating</strong> and commercial reputation</li>
      </ul>

      <p>This action may significantly impact your ability to conduct business and obtain credit in the future.</p>
    </div>

    <!-- Final Deadline -->
    <div class="deadline-box">
      <h2>FINAL PAYMENT DEADLINE</h2>
      <p class="deadline-date">{{$now.plus(( $('Configuration').first().json['Z days after due date'] - $('Configuration').first().json['Y days after due date'] ), 'days').format('MMMM dd, yyyy')}}</p>
      <p>You have {{( $('Configuration').first().json['Z days after due date'] - $('Configuration').first().json['Y days after due date'] )}} days from the date of this notice to settle this debt in full</p>
      <p>After this date, legal proceedings will commence without further notice</p>
    </div>

    <!-- Payment Information -->
    <div class="payment-section">
      <h2>Immediate Payment Required</h2>
      <p><strong>To avoid legal action, payment must be received by the deadline stated above.</strong></p>
      <div class="payment-details">
        <p><strong>Bank Name:</strong> {{$('Your Company Details').first().json['Bank Name']}}</p>
        <p><strong>Account Number:</strong> {{$('Your Company Details').first().json['Bank Account Number']}}</p>
        <p><strong>SWIFT Code:</strong> {{$('Your Company Details').first().json['Swift Code']}}</p>
        <p><strong>Payment Reference:</strong> {{$json['PelnyNumer']}} (MANDATORY)</p>
      </div>
      <p style="margin-top: 15px; color: #c62828;"><strong>Important:</strong> Include the invoice number in your payment reference to ensure proper allocation.</p>
    </div>

    <p><strong>Proof of Payment Required:</strong> Upon payment, immediately send proof of transfer to {{$('Your Company Details').first().json['Email']}} to halt legal proceedings.</p>

    <p><strong>Dispute of Debt:</strong> If you dispute this debt, you must provide written notice with supporting documentation within {{ $('Configuration').first().json['Z days after due date'] - $('Configuration').first().json['Y days after due date'] }} business days. Failure to do so will be considered acknowledgment of the debt.</p>

    <!-- Formal Signature -->
    <div class="formal-signature">
      <p>This notice is issued in accordance with applicable debt collection regulations.</p>

      <p style="margin-top: 20px;">
        Respectfully,<br><br>
        <strong>Legal & Collections Department</strong><br>
        {{$('Your Company Details').first().json['Company Name']}}<br>
        {{$('Your Company Details').first().json['Email']}}<br>
        {{$('Your Company Details').first().json['Phone']}}
      </p>

      <p style="margin-top: 20px; font-size: 12px; color: #999999;">
        <strong>Date of Notice:</strong> {{$now.format('MMMM dd, yyyy')}}<br>
        <strong>Reference Number:</strong> LEGAL-{{$json['Invoice Id']}}-{{$now.format('yyyyMMdd')}}
      </p>
    </div>

    <!-- Footer -->
    <div class="footer">
      <p><strong>{{$('Your Company Details').first().json['Company Name']}}</strong></p>
      <p>{{$('Your Company Details').first().json['Country Code']}} | {{$('Your Company Details').first().json['City']}}, {{$('Your Company Details').first().json['Street']}} | {{$('Your Company Details').first().json['Postal Code']}}</p>
      <p>TIN: {{$('Your Company Details').first().json['TIN (Tax Identification Number)']}}</p>
      <hr style="margin: 15px 0; border: none; border-top: 1px solid #e0e0e0;">
      <p style="font-size: 11px; color: #999999;">
        <strong>LEGAL NOTICE:</strong> This communication constitutes a formal demand for payment and notice of intent to commence legal proceedings. 
        This message is sent from an automated system but represents official legal correspondence. 
        All communications regarding this matter should be directed to our legal department at the contact details provided above.
      </p>
      <p style="font-size: 11px; color: #999999; margin-top: 10px;">
        Preservation Notice: Please retain this notice for your records. It may be presented as evidence in legal proceedings.
      </p>
    </div>
  </div>
</body>
</html>

